import { mkdir, readFile, writeFile } from 'node:fs/promises';
import { dirname, resolve } from 'node:path';

const repoRoot = resolve(import.meta.dirname, '..');
const source = resolve(repoRoot, 'src/api/contracts/v1.ts');
const frontendTarget = resolve(
  repoRoot,
  '../trip-planner-frontend-nextjs/src/services/api/contracts/v1.ts'
);

const header = `// Generated from trip-planner-backend-expressjs/src/api/contracts/v1.ts.
// Do not edit this file by hand; update the backend contract and sync it.

`;

await mkdir(dirname(frontendTarget), { recursive: true });
const contract = await readFile(source, 'utf8');
await writeFile(frontendTarget, `${header}${contract}`, 'utf8');

console.log(`Synced API contract to ${frontendTarget}`);
